```class Solution {
public:
    int possibleStringCount(string word, int k) {
        int count = 1;
        for (int i = 0; i < word.length(); i++) {
            int count_without_i = count;
            for (int j = i + 1; j < word.length(); j++) {
                count *= (word[j] == word[i]);
                count %= (1000000007);
            }
            count /= count_without_i;
        }
        return count;
    }
};
